<script lang="ts">
	import { onMount, untrack } from "svelte";
	import { busWebSocketUrl } from "$lib/api/client";
	import { opDef } from "$lib/api/ops";
	import type { CardItem, SignalEmission } from "$lib/api/types";
	import type { DeliveryReceiptView } from "$lib/data/signals";
	import Icon from "$lib/components/Icon.svelte";
	import OpButton from "$lib/components/OpButton.svelte";
	import StatusPill from "$lib/components/StatusPill.svelte";

	let { data } = $props();
	let pane = $state<"feed" | "delivery">("feed");
	let voidOpen = $state(false);
	let voidFilter = $state("");
	let signals = $state<SignalEmission[]>([...untrack(() => data.signals)]);
	let receipts = $state<DeliveryReceiptView[]>([...untrack(() => data.receipts)]);
	let busState = $state<"live" | "connecting" | "silent" | "gap">(untrack(() => data.isMock) ? "live" : "connecting");
	let heartbeatAt = $state<string | null>(untrack(() => data.isMock) ? new Date().toISOString() : null);
	let selectedSignal = $state<SignalEmission | null>(null);
	let selectedCard = $state<CardItem | null>(null);
	let drawer = $state<HTMLDialogElement | null>(null);
	let targetDialog = $state<HTMLDialogElement | null>(null);
	let target = $state(untrack(() => data.delivery?.target) ?? "");
	let newPattern = $state("");

	const snooze = opDef("signal.snooze")!;
	const subSet = opDef("subscription.set")!;
	const subRemove = opDef("subscription.remove")!;
	const repost = opDef("card.repost")!;
	const park = opDef("card.park")!;
	const test = opDef("delivery.test")!;
	const setTarget = opDef("delivery.set_target")!;
	const resend = opDef("delivery.resend")!;
	const cocoon = opDef("delivery.cocoon")!;
	const age = (ts: string) => { const s = Math.max(0, Math.round((Date.now() - Date.parse(ts)) / 1000)); return s < 60 ? `${s}s` : s < 3600 ? `${Math.round(s / 60)}m` : s < 86400 ? `${Math.round(s / 3600)}h` : `${Math.round(s / 86400)}d`; };
	const severityLabel = (severity: SignalEmission["severity"]) => ({ p0: "P0", danger: "P0", warn: "P1", info: "P2", debug: "P3" })[severity];
	const dead = $derived(data.cards.filter((card) => card.state === "dead"));
	const parked = $derived(data.cards.filter((card) => card.state === "parked"));
	const visibleSignals = $derived(signals.filter((signal) => `${signal.type} ${signal.subject} ${signal.source.service} ${signal.scope}`.toLowerCase().includes(voidFilter.toLowerCase())).slice(0, 50));
	const escapePattern = (part: string) => part.replaceAll(/[.*+?^${}()|[\]\\]/g, "\\$&");
	const globMatches = (pattern: string, type: string) => new RegExp(`^${pattern.split(".").map((part) => part === "**" ? ".+" : part === "*" ? "[^.]+" : escapePattern(part)).join("\\.")}$`).test(type);
	const feedSignals = $derived(visibleSignals.filter((signal) => data.subscriptions.some((subscription) => subscription.tier === "feed" && globMatches(subscription.pattern, signal.type))));
	const failedReceipts = $derived(receipts.filter((receipt) => receipt.status === "failed"));
	const recentFailures = $derived(receipts.slice(0, 2).filter((receipt) => receipt.status === "failed" && Date.now() - Date.parse(receipt.ts) <= 10 * 6e4));
	const matrixSyncDark = $derived(data.matrixSyncOkEpoch != null && data.matrixSyncOkEpoch > 0 && Date.now() / 1000 - data.matrixSyncOkEpoch > 120);
	const deliveryFailing = $derived(recentFailures.length === 2 || matrixSyncDark);
	const latestTest = $derived(receipts.find((receipt) => receipt.tier === "test" || receipt.signal === "delivery.test") ?? null);
	const nextSeven = () => { const d = new Date(); d.setHours(7, 0, 0, 0); if (d <= new Date()) d.setDate(d.getDate() + 1); return d.toISOString(); };

	$effect(() => { if ((selectedSignal || selectedCard) && drawer && !drawer.open) drawer.showModal(); });

	onMount(() => {
		if (data.isMock) return;
		let disposed = false;
		let lastSeq = Number(signals[0]?.id) || undefined;
		let ws: WebSocket | null = null;
		let reconnect: ReturnType<typeof setTimeout> | null = null;
		const connect = () => {
			ws = new WebSocket(busWebSocketUrl());
			ws.addEventListener("open", () => ws?.send(JSON.stringify({ schema_version: 1, action: "subscribe", sub_id: "console-signals", pattern: "**", ...(lastSeq ? { since: lastSeq } : {}) })));
			ws.addEventListener("message", (message) => {
			const frame = JSON.parse(String(message.data)) as { kind?: string; emission?: SignalEmission; ts?: string; seq?: number; ingest?: Record<string, number> | null };
			if (frame.kind === "heartbeat") { heartbeatAt = frame.ts ?? new Date().toISOString(); busState = frame.ingest && Object.values(frame.ingest).every((lag) => lag <= 90) ? "live" : "silent"; }
			if (frame.kind === "event" && frame.emission) {
				lastSeq = frame.seq ?? lastSeq;
				signals = [frame.emission, ...signals.filter((signal) => signal.id !== frame.emission?.id)].slice(0, 50);
				if (frame.emission.type === "delivery.receipt") receipts = [{ seq: frame.emission.id, ts: frame.emission.ts, tier: String(frame.emission.dimensions?.tier ?? "unknown"), signal: String(frame.emission.dimensions?.signal_ref ?? frame.emission.type), subject: frame.emission.subject, status: String(frame.emission.dimensions?.status ?? "unknown"), error: frame.emission.dimensions?.error_code ? String(frame.emission.dimensions.error_code) : null, retryable: frame.emission.dimensions?.retryable === true }, ...receipts].slice(0, 50);
			}
			if (frame.kind === "gap" || frame.kind === "resync_required") { busState = "gap"; globalThis.location.reload(); }
			});
			ws.addEventListener("error", () => (busState = "silent"));
			ws.addEventListener("close", () => { busState = "silent"; if (!disposed) reconnect = setTimeout(connect, 2000); });
		};
		connect();
		const freshness = setInterval(() => { if (heartbeatAt && Date.now() - Date.parse(heartbeatAt) > 9e4) busState = "silent"; }, 15000);
		return () => { disposed = true; if (reconnect) clearTimeout(reconnect); clearInterval(freshness); ws?.close(); };
	});

	function keyboard(event: KeyboardEvent) {
		if (event.key === "Escape" && voidOpen) voidOpen = false;
		if (event.key === "q" && document.activeElement?.hasAttribute("data-signal-row")) {
			const pattern = document.activeElement.getAttribute("data-pattern");
			if (pattern) document.querySelector<HTMLButtonElement>(`[data-quiet="${CSS.escape(pattern)}"]`)?.click();
		}
		const rows = Array.from(document.querySelectorAll<HTMLElement>("[data-signal-row]"));
		const index = rows.indexOf(event.target as HTMLElement);
		if ((event.key === "ArrowDown" || event.key === "ArrowUp") && index >= 0) { event.preventDefault(); rows[Math.max(0, Math.min(rows.length - 1, index + (event.key === "ArrowDown" ? 1 : -1)))]?.focus(); }
	}
</script>

<svelte:window onkeydown={keyboard} />

<header class="sign">
	<h1><Icon name="stamp" size={16} />Correspondence</h1><span>Signals · {pane === "feed" ? "System Bus" : "The Mindy Line"}</span>
		<small class:good={busState === "live"} class:bad={busState !== "live"}><Icon name={busState === "live" ? "circle-check" : "circle-help"} size={13} />{busState === "live" ? `Bus live · heartbeat ${heartbeatAt ? age(heartbeatAt) : "now"} ago` : busState === "gap" ? "Bus gap. Re-read required." : "Can't verify. Bus silent."}</small>
	<div class="sign-actions"><button class="ghost" onclick={() => { voidOpen = !voidOpen; pane = "feed"; }}><Icon name="search" size={13} />{voidOpen ? "Close the Void" : "Open the Void"}</button><div class="seg" aria-label="Signals pane"><button class:on={pane === "feed"} onclick={() => pane = "feed"}>Feed</button><button class:on={pane === "delivery"} onclick={() => pane = "delivery"}>Delivery</button></div></div>
</header>

{#if data.errors.length}<div class="verify"><Icon name="circle-help" size={15} />{data.errors.join(" · ")}. Available planes continue below.</div>{/if}

{#if pane === "feed"}
	{#if voidOpen}
		<section class="panel void"><header><div><h2>The Void</h2><span>every scoped event, subscribed or not</span></div><label><Icon name="search" size={13} /><input bind:value={voidFilter} aria-label="Filter the Void" placeholder="filter type, subject, source" /></label></header><div class="table-head"><span>when</span><span>severity</span><span>type</span><span>subject</span><span>source</span><span></span></div>{#each visibleSignals as signal}<div class="void-row"><button data-signal-row data-pattern={signal.type} class="row-open" onclick={() => selectedSignal = signal}><time>{new Date(signal.ts).toLocaleTimeString()}</time><b>{severityLabel(signal.severity)}</b><code>{signal.type}</code><span>{signal.subject}</span><code>{signal.source.agent ?? signal.source.service}</code></button><OpButton def={subSet} args={{ pattern: signal.type, tier: "feed" }} lanes={data.lanes} executorLive={data.consoleLive} label="Subscribe" /></div>{:else}<div class="empty">Nothing in the Void for that filter.</div>{/each}<footer>stats.query · {visibleSignals.length} events · {data.isMock ? "fixture" : "lake"}</footer></section>
	{:else}
		<div class="layout"><main>
			<section class="panel feed"><header><div><h2>Your feed</h2><span>{data.subscriptions.length} scopes subscribed</span></div><small>newest first</small></header>{#if data.isMock}<div class="digest"><button><Icon name="bell" size={14} /><code>container.update.*</code><b>6</b><span>batched 18:00</span><Icon name="chevron-right" size={14} /></button></div>{/if}{#each feedSignals as signal}<div class="signal"><button data-signal-row data-pattern={signal.type} class="row-open" onclick={() => selectedSignal = signal}><span class={`dot ${signal.severity}`}></span><b class={`sev ${signal.severity}`}>{severityLabel(signal.severity)}</b><code>{signal.type.split(".").at(-1)}</code><span class="subject">{signal.subject}</span><small>{signal.source.agent ?? signal.source.service}{signal.source.host ? `@${signal.source.host}` : ""}</small></button>{#if signal.action}<a class="look" href={signal.action}>look here</a>{:else}<span></span>{/if}<span data-quiet={signal.type} class="quiet"><OpButton def={snooze} args={{ type_pattern: signal.type, duration_s: 3600 }} lanes={data.lanes} executorLive={data.consoleLive} label="Quiet 1h" /></span><time>{age(signal.ts)}</time></div>{:else}<div class="empty">No mail for you. The void holds the rest.</div>{/each}<footer>Older mail rests in the Void.</footer></section>
			<section class="panel"><header><div><h2>Dead letters</h2><span>wanted board triage</span></div><small>{dead.length} dead · {parked.length} parked</small></header>{#each dead as card}<div class="dead"><Icon name="mail-x" size={14} /><a href={`/work?task=${card.task_id}`}>#{card.task_id}</a><b>{card.recipient ?? "pool"}</b><code>P{card.priority}</code><span>reaped {card.reaps} · fence {card.fence}</span><time>{age(new Date(card.updated_at_ms).toISOString())}</time><div class="ops"><OpButton def={repost} args={{ card_id: card.card_id }} lanes={data.lanes} executorLive={data.dispatcherLive} /><OpButton def={park} args={{ card_id: card.card_id }} lanes={data.lanes} executorLive={data.dispatcherLive} /><button class="ghost" onclick={() => selectedCard = card}>Inspect</button></div></div>{:else}<div class="empty"><Icon name="mailbox" size={14} />All caught up.</div>{/each}{#if parked.length}<div class="parked"><Icon name="clock" size={14} />{parked.length} parked, waiting on capacity · {parked.flatMap((card) => card.needs).join(", ") || "no eligible worker"}</div>{/if}</section>
		</main><aside>
			<section class="panel"><header><div><h2>Subscriptions</h2><span>the light menu</span></div></header>{#each data.subscriptions as subscription}<div class="sub"><div><code>{subscription.pattern}</code>{#if subscription.filter}<small>Filtered · edit through Janet; the current op cannot preserve this filter.</small>{:else}<div class="seg tiers">{#each ["feed", "digest", "interrupt"] as tier}<OpButton def={subSet} args={{ pattern: subscription.pattern, tier, loud: subscription.loud ?? false, note: subscription.note ?? "", window: subscription.window ?? undefined }} lanes={data.lanes} executorLive={data.consoleLive} variant={subscription.tier === tier ? "tonal" : "ghost"} label={tier[0].toUpperCase() + tier.slice(1)} />{/each}</div><OpButton def={subSet} args={{ pattern: subscription.pattern, tier: subscription.tier, loud: !subscription.loud, note: subscription.note ?? "", window: subscription.window ?? undefined }} lanes={data.lanes} executorLive={data.consoleLive} variant={subscription.loud ? "tonal" : "ghost"} label={subscription.loud ? "Loud" : "Quiet"} />{/if}</div><small>{subscription.updated_by ?? "unknown"} set this · {subscription.updated_at ? age(subscription.updated_at) : "time unknown"} ago</small><span class="remove"><OpButton def={subRemove} args={{ pattern: subscription.pattern }} lanes={data.lanes} executorLive={data.consoleLive} /></span></div>{:else}<div class="empty">No standing subscriptions returned.</div>{/each}<div class="add"><input bind:value={newPattern} aria-label="New subscription pattern" placeholder="add a scope pattern" /><OpButton def={subSet} args={{ pattern: newPattern, tier: "feed" }} lanes={data.lanes} executorLive={data.consoleLive} label="Add" /></div><footer>Edit here or ask Janet. Changes audit.</footer></section>
			<section class="panel ladder"><h2>Escalation ladder</h2><p><Icon name="inbox" size={14} /><b>Feed</b><span>stays in your feed</span></p><p><Icon name="bell" size={14} /><b>Digest</b><span>batched on schedule</span></p><small><Icon name="arrow-up" size={12} />promote to loud opts a scope up</small><p><Icon name="siren" size={14} /><b>Interrupt</b><span>reaches you off-console</span></p><footer>Interrupt is reserved: P0, safety, principal command.</footer></section>
			<button class="panel pointer" onclick={() => pane = "delivery"}><Icon name="send" size={14} /><span><b>The Mindy Line</b><small>Interrupts and loud scopes leave the console via Matrix.</small></span></button>
		</aside></div>
	{/if}
{:else}
	{#if deliveryFailing}<section class="crack" aria-live="polite"><Icon name="triangle-alert" size={18} /><div><b>Matrix delivery failing. Interrupts are NOT reaching you. Shown here as backup.</b><span>{failedReceipts.length} failed receipts · recovery remains hot</span>{#each recentFailures as receipt}<code><Icon name="siren" size={12} />{new Date(receipt.ts).toLocaleTimeString()} · {receipt.tier} · {receipt.signal} · shown here, not delivered</code>{/each}</div><OpButton def={test} args={{}} lanes={data.lanes} executorLive={data.consoleLive} variant="primary" /><button class="ghost" onclick={() => targetDialog?.showModal()}>Change target</button></section>{/if}
	<div class="delivery-grid"><main><section class="panel target"><h2>Where interrupts reach you</h2><span>Per user. This line is yours.</span>{#if data.delivery}<div class="target-row"><Icon name="message-square" size={16} /><b>Matrix DM</b><code>{data.delivery.target}</code><StatusPill tone={deliveryFailing ? "danger" : data.delivery.verified ? "good" : "warn"} label={deliveryFailing ? "failing" : data.delivery.verified ? "verified" : "unverified"} /></div><div class="actions"><OpButton def={test} args={{}} lanes={data.lanes} executorLive={data.consoleLive} /><button class="ghost" onclick={() => targetDialog?.showModal()}>Change target</button></div>{#if latestTest}<div class:result-good={latestTest.status === "delivered"} class:result-bad={latestTest.status !== "delivered"} class="test-result" aria-live="polite">{latestTest.status === "delivered" ? `Delivered ${new Date(latestTest.ts).toLocaleTimeString()}. The line works.` : `Failed. ${latestTest.error ?? "No receipt detail returned."}`}</div>{/if}<div class="cocoon"><Icon name="bell-off" size={16} /><b>Cocoon mode</b><div class="seg"><OpButton def={cocoon} args={{ until: new Date().toISOString() }} lanes={data.lanes} executorLive={data.consoleLive} variant={!data.delivery.cocoon_until ? "tonal" : "ghost"} label="Off" /><OpButton def={cocoon} args={{ until: nextSeven() }} lanes={data.lanes} executorLive={data.consoleLive} variant={data.delivery.cocoon_until ? "tonal" : "ghost"} label="Until 07:00" /></div><span>P0 and safety always come through.</span></div><footer>configured by {data.delivery.updated_by} · {age(data.delivery.updated_at)} ago · audited</footer>{:else}<div class="empty"><Icon name="phone-forwarded" size={16} />The Mindy Line is not connected. Interrupts show only here.</div><button class="primary" onclick={() => targetDialog?.showModal()}>Connect Matrix</button>{/if}</section>
	<section class="panel ladder wide"><h2>What gets through</h2><p><Icon name="inbox" size={16} /><b>Feed</b><span>Rests in the void. Never sent off-console.</span></p><p><Icon name="bell" size={16} /><b>Digest</b><span>Batched, polite, on schedule.</span><code>{data.delivery?.next_digest_at ? `next ${new Date(data.delivery.next_digest_at).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}` : "on demand"}</code></p><p><Icon name="siren" size={16} /><b>Interrupt</b><span>Sent to the Mindy Line the moment it fires.</span><code>Category 55</code></p><footer>{data.subscriptions.filter((subscription) => subscription.loud).length} subscriptions marked loud. <button onclick={() => pane = "feed"}>Open the subscribe menu</button></footer></section>
	<section class="panel receipts"><h2>Delivery log</h2><span>Recent off-console sends</span><div class="receipt-head"><span>when</span><span>tier</span><span>signal</span><span>result</span><span>channel</span></div>{#if !data.receiptsAvailable}<div class="empty">Query failed. Nothing rendered, nothing pretended.</div>{:else}{#each receipts as receipt}<details><summary><time>{new Date(receipt.ts).toLocaleTimeString()}</time><code>{receipt.tier}</code><span><b>{receipt.signal}</b> · {receipt.subject}</span><StatusPill tone={receipt.status === "delivered" ? "good" : "danger"} label={receipt.status} /><code>matrix</code></summary>{#if receipt.error}<p>Error: {receipt.error}</p>{#if receipt.retryable}<OpButton def={resend} args={{ receipt_ref: receipt.seq }} lanes={data.lanes} executorLive={data.consoleLive} />{/if}{:else}<p>Receipt {receipt.seq} · delivered and persisted.</p>{/if}</details>{:else}<div class="empty">No off-console sends yet.</div>{/each}{/if}<footer>stats.query · {receipts.length} receipts · {data.isMock ? "fixture" : "lake"}</footer></section></main><aside><section class="panel note"><Icon name="smartphone" size={16} /><div><h2>Every device, one line</h2><p>Matrix fans out to every device you are signed in on. Nothing to configure per device.</p></div></section><section class="panel note"><Icon name="flask-conical" size={16} /><div><h2>Under evaluation</h2><p>ntfy with UnifiedPush, and a native lab app. Adopted only if proven better on your devices.</p></div></section></aside></div>
{/if}

<dialog bind:this={drawer} aria-labelledby="drawer-title" onclose={() => { selectedSignal = null; selectedCard = null; }}><button class="x" aria-label="Close details" onclick={() => drawer?.close()}><Icon name="x" size={16} /></button>{#if selectedSignal}<h2 id="drawer-title">{selectedSignal.type}</h2><p>{selectedSignal.subject}</p><dl><dt>severity</dt><dd>{selectedSignal.severity} · {severityLabel(selectedSignal.severity)}</dd><dt>source</dt><dd>{selectedSignal.source.agent ?? selectedSignal.source.service}</dd><dt>scope</dt><dd>{selectedSignal.scope}</dd><dt>time</dt><dd>{selectedSignal.ts}</dd>{#if selectedSignal.task_id}<dt>task</dt><dd><a href={`/work?task=${selectedSignal.task_id}`}>#{selectedSignal.task_id}</a></dd>{/if}</dl><pre>{JSON.stringify(selectedSignal, null, 2)}</pre><div class="actions"><OpButton def={subSet} args={{ pattern: selectedSignal.type, tier: "feed" }} lanes={data.lanes} executorLive={data.consoleLive} label="Subscribe to this scope" /><OpButton def={snooze} args={{ type_pattern: selectedSignal.type, duration_s: 3600 }} lanes={data.lanes} executorLive={data.consoleLive} /></div>{:else if selectedCard}<h2 id="drawer-title">Card #{selectedCard.task_id}</h2><p>{selectedCard.body}</p><dl><dt>sender</dt><dd>{selectedCard.sender} · {selectedCard.sender_class}</dd><dt>recipient</dt><dd>{selectedCard.recipient ?? "pool"}</dd><dt>reaps</dt><dd>{selectedCard.reaps}</dd><dt>fence</dt><dd>{selectedCard.fence}</dd></dl><h3>Lifecycle</h3><p>posted → claimed → reaped/re-posted → dead</p><div class="actions"><OpButton def={repost} args={{ card_id: selectedCard.card_id }} lanes={data.lanes} executorLive={data.dispatcherLive} /><OpButton def={park} args={{ card_id: selectedCard.card_id }} lanes={data.lanes} executorLive={data.dispatcherLive} /></div>{/if}</dialog>

<dialog bind:this={targetDialog} aria-labelledby="target-title"><button class="x" aria-label="Close target dialog" onclick={() => targetDialog?.close()}><Icon name="x" size={16} /></button><h2 id="target-title">Change Matrix target</h2><p>The old target stays live until the new one passes a test.</p><label>Matrix room or user<input bind:value={target} pattern="^!.+:.+$|^@.+:.+$" /></label><div class="actions"><OpButton def={setTarget} args={{ channel: "matrix", target }} lanes={data.lanes} executorLive={data.consoleLive} variant="primary" /><button class="ghost" onclick={() => targetDialog?.close()}>Cancel</button></div></dialog>

<style>
	.sign{display:flex;align-items:center;gap:var(--s-3);min-height:40px}.sign h1{display:flex;align-items:center;gap:var(--s-2);font:400 1.25rem var(--sign)}.sign>span,.sign small{font-size:.75rem;color:var(--text-3)}.sign small{display:flex;align-items:center;gap:var(--s-1);color:var(--warn-text)}.sign small.good{color:var(--jade-text)}.sign-actions{margin-left:auto;display:flex;gap:var(--s-2)}button{font:500 .75rem var(--sans)}.ghost,.primary{border:0;background:none;color:var(--petal-text);min-height:32px;padding:0 var(--s-2);border-radius:var(--r-sm);display:inline-flex;align-items:center;gap:var(--s-1)}.ghost:hover{background:var(--s2)}.primary{background:var(--petal-fill);color:var(--on-petal)}.seg{display:flex;background:var(--s2);padding:2px;border-radius:var(--r-pill)}.seg>button{border:0;background:none;color:var(--text-3);border-radius:var(--r-pill);min-height:28px;padding:0 var(--s-3)}.seg>button.on{background:var(--petal-soft);color:var(--petal-text)}.verify,.crack{display:flex;align-items:center;gap:var(--s-2);padding:var(--s-3);margin:var(--s-2) 0;border-radius:var(--r-xs);background:var(--warn-soft);color:var(--warn-text);font-size:.75rem}.crack{background:var(--danger-soft);color:var(--danger-text)}.crack div{display:grid;margin-right:auto}.crack span{color:var(--text-3)}.layout,.delivery-grid{display:grid;grid-template-columns:minmax(0,600px) minmax(280px,344px);gap:var(--s-3);align-items:start}.layout>main,.layout>aside,.delivery-grid>main,.delivery-grid>aside{display:flex;flex-direction:column;gap:var(--s-3)}.panel{background:var(--s1);border-radius:var(--r-xs);padding:var(--s-3);color:var(--text)}.panel>header{display:flex;align-items:center;min-height:32px}.panel header>div{display:flex;gap:var(--s-2);align-items:baseline}.panel h2{font-size:.8125rem}.panel header span,.panel>span,.panel header small{font-size:.6875rem;color:var(--text-3)}.panel header small{margin-left:auto}.panel footer{font-size:.6875rem;color:var(--text-3);padding-top:var(--s